_sec":12,"end_time_sec":14.4,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":5,"chord_name":"C/G","measure_number":7,"beat_offset":1,"duration_beats":4,"start_time_sec":14.399999999999999,"end_time_sec":16.799999999999997,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":6,"chord_name":"—","measure_number":8,"beat_offset":1,"duration_beats":4,"start_time_sec":16.8,"end_time_sec":19.2,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":7,"chord_name":"C/G","measure_number":9,"beat_offset":1,"duration_beats":4,"start_time_sec":19.2,"end_time_sec":21.599999999999998,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":8,"chord_name":"—","measure_number":10,"beat_offset":1,"duration_beats":4,"start_time_sec":21.599999999999998,"end_time_sec":23.999999999999996,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":9,"chord_name":"C/G","measure_number":11,"beat_offset":1,"duration_beats":4,"start_time_sec":24,"end_time_sec":26.4,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":10,"chord_name":"—","measure_number":12,"beat_offset":1,"duration_beats":4,"start_time_sec":26.4,"end_time_sec":28.799999999999997,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":11,"chord_name":"C/G","measure_number":13,"beat_offset":1,"duration_beats":4,"start_time_sec":28.799999999999997,"end_time_sec":31.199999999999996,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":12,"chord_name":"—","measure_number":14,"beat_offset":1,"duration_beats":4,"start_time_sec":31.2,"end_time_sec":33.6,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":13,"chord_name":"C/G","measure_number":15,"beat_offset":1,"duration_beats":4,"start_time_sec":33.6,"end_time_sec":36,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":14,"chord_name":"—","measure_number":16,"beat_offset":1,"duration_beats":4,"start_time_sec":36,"end_time_sec":38.4,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":15,"chord_name":"C/G","measure_number":17,"beat_offset":1,"duration_beats":4,"start_time_sec":38.4,"end_time_sec":40.8,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":16,"chord_name":"—","measure_number":18,"beat_offset":1,"duration_beats":4,"start_time_sec":40.8,"end_time_sec":43.199999999999996,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":17,"chord_name":"C/G","measure_number":19,"beat_offset":1,"duration_beats":4,"start_time_sec":43.199999999999996,"end_time_sec":45.599999999999994,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":18,"chord_name":"—","measure_number":20,"beat_offset":1,"duration_beats":4,"start_time_sec":45.6,"end_time_sec":48,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":19,"chord_name":"C/G","measure_number":21,"beat_offset":1,"duration_beats":4,"start_time_sec":48,"end_time_sec":50.4,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":20,"chord_name":"—","measure_number":22,"beat_offset":1,"duration_beats":4,"start_time_sec":50.4,"end_time_sec":52.8,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":21,"chord_name":"C/G","measure_number":23,"beat_offset":1,"duration_beats":4,"start_time_sec":52.8,"end_time_sec":55.199999999999996,"voicing":["C4","G4"],"voicing_staves":[1,1]},{"order_index":22,"chord_name":"—","measure_number":24,"beat_offset":1,"duration_beats":4,"start_time_sec":55.199999999999996,"end_time_sec":57.599999999999994,"voicing":[],"voicing_staves":[],"input_disabled":true},{"order_index":23,"chord_name":"C/G","measure_number":25,"beat_offset":1,"duration_beats":4,"start_time_sec":57.599999999999994,"end_time_sec":59.99999999999999,"voicing":["C4","G4"],"voicing_staves":[1,1]}]}]}},"scenes":[{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"ファイよ、この世界は音のチカラを失い、崩れかけておる。","en":"Fai, this world has lost the power of sound and is crumbling."},{"speaker":"player","ja":"えっ、オレが何とかするの？","en":"Wait — I have to fix this?"},{"speaker":"partner","ja":"うむ。必要なのは、ジャズのチカラじゃ。","en":"Aye. What we need is the power of jazz."},{"speaker":"player","ja":"ジャズって、むずかしそうだけど。","en":"Jazz sounds pretty hard though."},{"speaker":"partner","ja":"心配いらん。まず使う音は、ドとソだけじゃ。","en":"Fear not. For now you only need Do and Sol."},{"speaker":"player","ja":"2つだけなら、いけそう！","en":"Only two notes — I can do that!"},{"speaker":"partner","ja":"ワシの音を1小節聴き、次の1小節でまねするのじゃ。","en":"Listen for one bar, then copy me in the next bar."},{"speaker":"player","ja":"まずは、ドとソをまねしてみよう。","en":"Let''s start by copying Do and Sol."}]},{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"このコースでは、Cブルースに挑戦する。","en":"In this course we take on the C blues."},{"speaker":"player","ja":"Cブルース？","en":"C blues?"},{"speaker":"partner","ja":"ジャズの入口にぴったりの流れじゃ。","en":"A perfect entry into jazz."},{"speaker":"player","ja":"いきなり曲っぽいことするんだね。","en":"So we jump into something song-like right away."},{"speaker":"partner","ja":"そうじゃ。読むより先に、聴いて、返して、手で覚えるのじゃ。","en":"Aye. Hear, answer, and learn with your hands before reading."},{"speaker":"player","ja":"よし、まずは音で会話だ！","en":"Alright — conversation with sound first!"},{"speaker":"player","ja":"流れる音を聴いて、次の小節で同じように返そう。","en":"Listen to the music, then answer the same way in the next bar."}]},{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"上の楽譜が進む。光る音をよく見るのじゃ。","en":"The score above moves. Watch the highlighted notes."},{"speaker":"player","ja":"聴くところと、弾くところが交互に来るんだね。","en":"Listen bars and play bars alternate."},{"speaker":"partner","ja":"うむ。聴く小節では聴く。返す小節で弾く。","en":"Aye. Listen on listen bars. Play on answer bars."},{"speaker":"player","ja":"あわてず、ドとソをねらえばいいんだな。","en":"No rush — just aim for Do and Sol."},{"speaker":"player","ja":"1小節聴いて、1小節まねしよう。","en":"One bar listen, one bar copy."}]},{"type":"chord_osmd","contentRef":"mq-b1-q1-osmd","requiredLoops":1,"timedLines":[{"at":{"loop":0,"measure":2,"beat":1},"text":{"ja":"聴く","en":"Listen"}},{"at":{"loop":0,"measure":3,"beat":1},"text":{"ja":"返す（ドとソ）","en":"Answer (Do & Sol)"}}]},{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"よし。ドとソで返事ができたのう。","en":"Good. You answered with Do and Sol."},{"speaker":"player","ja":"ちょっと音で会話してる感じがした！","en":"It felt like talking with sound!"},{"speaker":"partner","ja":"次は、まねるだけではない。","en":"Next, you won''t only copy."},{"speaker":"player","ja":"じゃあ、どうするの？","en":"So what do I do?"},{"speaker":"partner","ja":"ドとソだけで、自分の返事を弾くのじゃ。","en":"Answer in your own way with just Do and Sol."},{"speaker":"player","ja":"次は、ドとソで自由にアドリブしよう。","en":"Next up: ad-lib with Do and Sol."}]},{"type":"finish"}],"finish":{"showCta":true}}'::jsonb
)
