umber":17,"beat_offset":1,"duration_beats":4,"start_time_sec":38.4,"end_time_sec":40.8,"voicing":["E4","B♭4"],"voicing_staves":[1,1]},{"order_index":16,"chord_name":"F7","measure_number":18,"beat_offset":1,"duration_beats":4,"start_time_sec":40.8,"end_time_sec":43.199999999999996,"voicing":["E♭4","A4"],"voicing_staves":[1,1]},{"order_index":17,"chord_name":"F7","measure_number":19,"beat_offset":1,"duration_beats":4,"start_time_sec":43.199999999999996,"end_time_sec":45.599999999999994,"voicing":["E♭4","A4"],"voicing_staves":[1,1]},{"order_index":18,"chord_name":"C7","measure_number":20,"beat_offset":1,"duration_beats":4,"start_time_sec":45.6,"end_time_sec":48,"voicing":["E4","B♭4"],"voicing_staves":[1,1]},{"order_index":19,"chord_name":"C7","measure_number":21,"beat_offset":1,"duration_beats":4,"start_time_sec":48,"end_time_sec":50.4,"voicing":["E4","B♭4"],"voicing_staves":[1,1]},{"order_index":20,"chord_name":"G7","measure_number":22,"beat_offset":1,"duration_beats":4,"start_time_sec":50.4,"end_time_sec":52.8,"voicing":["F4","B4"],"voicing_staves":[1,1]},{"order_index":21,"chord_name":"F7","measure_number":23,"beat_offset":1,"duration_beats":4,"start_time_sec":52.8,"end_time_sec":55.199999999999996,"voicing":["E♭4","A4"],"voicing_staves":[1,1]},{"order_index":22,"chord_name":"C7","measure_number":24,"beat_offset":1,"duration_beats":4,"start_time_sec":55.199999999999996,"end_time_sec":57.599999999999994,"voicing":["E4","B♭4"],"voicing_staves":[1,1]},{"order_index":23,"chord_name":"G7","measure_number":25,"beat_offset":1,"duration_beats":4,"start_time_sec":57.599999999999994,"end_time_sec":59.99999999999999,"voicing":["F4","B4"],"voicing_staves":[1,1]}]}]}},"scenes":[{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"今度は、リズムに合わせる練習じゃ。","en":"Now we practice with the groove."},{"speaker":"player","ja":"全部弾くんじゃなくて、1拍目だけ？","en":"Not every beat — just beat one?"},{"speaker":"partner","ja":"そうじゃ。まずは小節の頭を感じる。","en":"Aye. Feel the top of each bar first."},{"speaker":"player","ja":"コードが変わる場所を、ちゃんと踏むんだね。","en":"Land where the chords change."},{"speaker":"partner","ja":"うむ。ジャズは音だけでなく、時間に乗る音楽じゃ。","en":"Jazz rides time, not just notes."},{"speaker":"player","ja":"リズムを聴いて、各小節の1拍目にコードを弾こう。","en":"Listen and hit each chord on beat one."}]},{"type":"chord_osmd","contentRef":"mq-b1-q3-osmd","requiredLoops":1,"timedLines":[{"at":{"loop":0,"measure":2,"beat":1},"text":{"ja":"1拍目","en":"Beat 1"}}]},{"type":"dialogue_only","lineIntervalSeconds":4,"lines":[{"speaker":"partner","ja":"見事じゃ。コードをリズムに乗せられたのう。","en":"Well done. You rode the rhythm with your chords."},{"speaker":"player","ja":"ただ押すより、音楽っぽくなった！","en":"It feels more musical than just pressing keys!"},{"speaker":"partner","ja":"これでCブルースの土台はできた。","en":"The foundation of C blues is in place."},{"speaker":"player","ja":"次はもっと自由に弾けそう！","en":"I feel ready to play more freely!"},{"speaker":"partner","ja":"うむ。響きとリズムの上で、アドリブは育つのじゃ。","en":"Aye. Ad-lib grows on harmony and rhythm."},{"speaker":"player","ja":"次のクエストへ進もう。","en":"On to the next quest."}]},{"type":"finish"}],"finish":{"showCta":true}}'::jsonb
)
